public:
    string concatHex36(int n) {
        long long n2 = static_cast<long long>(n) * n;
        long long n3 = n2 * n;

        string hex;
        if (n2 == 0) hex = "0";
        else {
            while (n2 > 0) {
                int rem = n2 % 16;
                hex.push_back(rem < 10 ? '0' + rem : 'A' + rem - 10);
                n2 /= 16;
            }
            reverse(hex.begin(), hex.end());
        }

        string hex36;
        if (n3 == 0) hex36 = "0";
        else {
            while (n3 > 0) {
                int rem = n3 % 36;
                hex36.push_back(rem < 10 ? '0' + rem : 'A' + rem - 10);
                n3 /= 36;
            }
            reverse(hex36.begin(), hex36.end());
        }

        return hex + hex36;
    }
};```
